// Nodo: "Normalizar Teléfono"
// Tipo: Code node
// Ubicación: Webhook → [Normalizar Teléfono] → Guardar en Buffer
// 
// Corrige el "1" extra: +52113311386582 → +5213311386582
// Formato correcto: +521 + 10 dígitos (13 dígitos después del +)

const body = $json.body || {};
let phone = String(body.telefono || "");

// Quitar espacios
phone = phone.trim();

// Fix: +5211XXXXXXXXXX → +521XXXXXXXXXX (quitar el "1" extra después de 521)
if (phone.startsWith("+5211") && phone.length === 15) {
  phone = "+52" + phone.slice(4); // quita el "1" extra
} else if (phone.startsWith("5211") && phone.length === 14) {
  phone = "52" + phone.slice(3);
}

return [{
  json: {
    body: {
      ...body,
      telefono: phone,
      telefonoOriginal: body.telefono,  // guardar original por si acaso
    }
  }
}];

// Code node: "Render Prompt" — AgendaFlow Sales Agent
// Input: HTTP Request (GitHub raw) con $json.data (texto del prompt)
// Output: content renderizado + campos de Mensaje Usuario

// 1) Toma el texto crudo del prompt de GitHub
const allItems = $input.all();
const docRaw = allItems[0].json.data ?? allItems[0].json.content ?? "";

// 2) Normaliza comillas curvas, NBSP, etc.
const normalizeFn = (s) =>
  s
    .replace(/[\u201C\u201D]/g, '"')
    .replace(/[\u2018\u2019]/g, "'")
    .replace(/\u00A0/g, " ");

// 3) Helpers de fecha/hora (locale ES y zona horaria)
const TZ = "America/Chihuahua";
const now = new Date();

function formatNowFull(d = now, tz = TZ) {
  const fmt = new Intl.DateTimeFormat("es-MX", {
    weekday: "long",
    day: "2-digit",
    month: "long",
    year: "numeric",
    hour: "2-digit",
    minute: "2-digit",
    second: "2-digit",
    hour12: false,
    timeZone: tz,
  });
  return fmt.format(d).replace(/^\p{L}/u, (m) => m.toLowerCase());
}

function formatISO(d = now, tz = TZ) {
  const parts = new Intl.DateTimeFormat("en-CA", {
    year: "numeric", month: "2-digit", day: "2-digit",
    hour: "2-digit", minute: "2-digit", second: "2-digit",
    hour12: false, timeZone: tz,
  }).formatToParts(d).reduce((acc, p) => (acc[p.type]=p.value, acc), {});
  return `${parts.year}-${parts.month}-${parts.day}T${parts.hour}:${parts.minute}:${parts.second}`;
}

// 4) Variables de contexto desde Mensaje Usuario
const Mensaje = $('Mensaje Usuario').first().json;
const telefono       = Mensaje?.telefono ?? "";
const userID         = Mensaje?.userID   ?? "";
const mensajeUsuario = Mensaje?.mensajeUsuario ?? "";
const demo           = Mensaje?.demo ?? "";
const lead_id        = Mensaje?.lead_id ?? 0;
const is_new_lead    = Mensaje?.is_new_lead ?? false;
const niche          = Mensaje?.niche ?? "";
const funnel_stage   = Mensaje?.funnel_stage ?? "new";

// 5) Buscar contexto adicional del lead
let lead_name = "";
let followup_count = 0;
try {
  const leadCtx = $('Buscar Lead Context').first().json;
  lead_name = leadCtx?.name || "";
  followup_count = leadCtx?.followup_count || 0;
} catch(e) {
  // Si no existe el nodo aún, usar defaults
}

// 6) Diccionario de reemplazo de placeholders
const vars = {
  now_full: formatNowFull(),
  now_iso: formatISO(),
  tz: TZ,
  telefono,
  userID,
  niche: niche || "desconocido",
  funnel_stage: funnel_stage || "new",
  lead_name: lead_name || "No disponible",
  followup_count: String(followup_count),
};

// 7) Render: reemplaza {{ clave }} por el valor
let rendered = normalizeFn(docRaw);

for (const [key, value] of Object.entries(vars)) {
  const re = new RegExp(`{{\\s*${key}\\s*}}`, "g");
  rendered = rendered.replace(re, String(value));
}

// 8) Output
return [{ json: {
  content: rendered,
  userID,
  telefono,
  lead_name,
  mensajeUsuario,
  demo,
  is_new_lead,
  niche,
  funnel_stage,
  lead_id
} }];

const webhookData = $('Webhook').first().json;
const combinedMessage = $('Verificar y Concatenar').first().json.combined_message || webhookData.body.mensaje || "";
const messageCount = $('Verificar y Concatenar').first().json.message_count || 1;

// Fix teléfono: +5211XXXXXXXXXX → +521XXXXXXXXXX
let phone = String(webhookData.body.telefono || "").trim();
if (phone.startsWith("+5211") && phone.length === 15) {
  phone = "+52" + phone.slice(4);
}

return [{
  json: {
    body: {
      ...webhookData.body,
      telefono: phone,
      mensaje: (combinedMessage || "").replace(/'/g, "''"),
      mensajeOriginal: webhookData.body.mensaje,
      mensajesAcumulados: Number(messageCount),
    }
  }
}];

