// Filtro Anti-Bot v1.0
// Nodo Code para n8n — Detecta mensajes de bots/agentes virtuales para evitar loops
// Ubicación en workflow: después de Code1 (normalización), ANTES de Guardar en Buffer

const mensaje = $json.body?.mensaje || "";
const telefono = $json.body?.telefono || "";

// ============================================================
// 1) LISTA NEGRA DE NÚMEROS — bots conocidos (agregar según se detecten)
// ============================================================
const BLACKLIST_PHONES = new Set([
  // Formato: número normalizado tal como lo entrega Code1
  // Ejemplo: "5213396900001",  // Mega Conecta
  // Ejemplo: "5215551234567",  // Telmex
]);

if (BLACKLIST_PHONES.has(telefono)) {
  return [{
    json: {
      ...$json,
      is_bot: true,
      bot_reason: "blacklist_phone"
    }
  }];
}

// ============================================================
// 2) PATRONES DE TEXTO — frases típicas de bots comerciales
// ============================================================
const BOT_PATTERNS = [
  // Auto-presentación de bots/asistentes virtuales
  /soy tu asistente virtual/i,
  /soy .{1,30} asistente virtual/i,
  /asistente virtual de /i,
  /soy un bot/i,
  /soy una inteligencia artificial/i,
  /chatbot/i,

  // Menús automatizados
  /selecciona una de las opciones/i,
  /elige una opci[oó]n/i,
  /escribe el n[uú]mero de la opci[oó]n/i,
  /responde con el n[uú]mero/i,
  /ver opciones/i,

  // Auto-respuestas empresariales
  /para una mejor experiencia/i,
  /para brindarte .{1,30} atenci[oó]n/i,
  /tenemos un whatsapp especial/i,
  /te invitamos a comunicarte/i,
  /mensaje autom[aá]tico/i,
  /respuesta autom[aá]tica/i,
  /este es un mensaje autom[aá]tico/i,
  /este canal no est[aá] monitoreado/i,
  /no responder a este mensaje/i,
  /enviado de forma autom[aá]tica/i,

  // Patrones de telecomunicaciones / servicios
  /contratar tu paquete/i,
  /incrementa sus velocidades/i,
  /relacionado a tu contrato/i,
  /soporte y todo lo relacionado/i,
  /al contratar tu paquete/i,
  /mejorar tu plan/i,
  /tu saldo es/i,
  /tu recibo est[aá] listo/i,

  // Links de redireccionamiento a otro WhatsApp Business
  /wa\.me\/\d{10,}/i,

  // Patrones de CRM/chatbot genéricos
  /no pudimos entender tu mensaje/i,
  /no entend[ií] tu respuesta/i,
  /por favor elige una/i,
  /te comparto las opciones/i,
  /escribe "hola" para comenzar/i,
  /escribe salir para terminar/i,
  /sesion finalizada/i,
  /sesi[oó]n expirada/i,

  // Confirmaciones automatizadas de sistemas
  /tu c[oó]digo de verificaci[oó]n/i,
  /c[oó]digo de seguridad/i,
  /tu c[oó]digo es: ?\d/i,
];

for (const pattern of BOT_PATTERNS) {
  if (pattern.test(mensaje)) {
    return [{
      json: {
        ...$json,
        is_bot: true,
        bot_reason: `pattern: ${pattern.source}`
      }
    }];
  }
}

// ============================================================
// 3) DENSIDAD DE EMOJIS + KEYWORDS — bots comerciales usan muchos emojis
// ============================================================
const emojiRegex = /[\u{1F600}-\u{1F64F}\u{1F300}-\u{1F5FF}\u{1F680}-\u{1F6FF}\u{1F1E0}-\u{1F1FF}\u{2702}-\u{27B0}\u{24C2}-\u{1F251}\u{1F900}-\u{1F9FF}\u{1FA00}-\u{1FA6F}\u{1FA70}-\u{1FAFF}\u{2600}-\u{26FF}\u{2700}-\u{27BF}]/gu;
const emojis = mensaje.match(emojiRegex) || [];
const words = mensaje.trim().split(/\s+/).length;

// 3+ emojis Y más del 20% del mensaje son emojis Y tiene keywords de bot
if (emojis.length >= 3 && (emojis.length / words) > 0.2) {
  if (/opciones|selecciona|elige|asistente|bot|autom[aá]tico|paquete|contrato|plan|saldo/i.test(mensaje)) {
    return [{
      json: {
        ...$json,
        is_bot: true,
        bot_reason: "emoji_density_with_bot_keywords"
      }
    }];
  }
}

// ============================================================
// 4) MENSAJES VACÍOS O SOLO MULTIMEDIA (sin texto)
//    No filtrar como bot — reemplazar con placeholder para que el agente responda
// ============================================================
const MEDIA_PLACEHOLDERS = {
  "": "[El lead envió un mensaje multimedia (imagen, video o audio). No tienes acceso al contenido multimedia.]",
  "[imagen]": "[El lead envió una imagen. No tienes acceso al contenido multimedia.]",
  "[audio]": "[El lead envió un audio. No tienes acceso al contenido multimedia.]",
  "[video]": "[El lead envió un video. No tienes acceso al contenido multimedia.]",
  "[sticker]": "[El lead envió un sticker. No tienes acceso al contenido multimedia.]",
};

const trimmed = mensaje.trim();
if (trimmed in MEDIA_PLACEHOLDERS) {
  return [{
    json: {
      body: {
        ...$json.body,
        mensaje: MEDIA_PLACEHOLDERS[trimmed],
        mensajeOriginal: mensaje,
      },
      is_bot: false,
      bot_reason: null
    }
  }];
}

// ============================================================
// 5) NO ES BOT — continuar flujo normal
// ============================================================
return [{
  json: {
    ...$json,
    is_bot: false,
    bot_reason: null
  }
}];
